1	import { Navigate } from 'react-router-dom';
2	import { useAuthStore } from '../../store/authStore';
3	
4	interface ProtectedRouteProps {
5	  children: React.ReactNode;
6	  roles?: string[];
7	}
8	
9	export function ProtectedRoute({ children, roles }: ProtectedRouteProps) {
10	  const { isAuthenticated, isBootstrapping, hasRole } = useAuthStore();
11	
12	  if (isBootstrapping) {
13	    return null;
14	  }
15	
16	  if (!isAuthenticated) {
17	    return <Navigate to="/login" replace />;
18	  }
19	
20	  if (roles && !roles.some((role) => hasRole(role))) {
21	    return <Navigate to="/" replace />;
22	  }
23	
24	  return <>{children}</>;
25	}
