1	import { create } from 'zustand';
2	import type { User } from '../types';
3	import { me } from '../api/auth';
4	
5	interface AuthState {
6	  user: User | null;
7	  roles: string[];
8	  isAuthenticated: boolean;
9	  isBootstrapping: boolean;
10	  setAuth: (user: User, roles: string[]) => void;
11	  clearAuth: () => void;
12	  hasRole: (role: string) => boolean;
13	  bootstrap: () => Promise<void>;
14	}
15	
16	export const useAuthStore = create<AuthState>((set, get) => ({
17	  user: null,
18	  roles: [],
19	  isAuthenticated: false,
20	  isBootstrapping: true,
21	  setAuth: (user, roles) => set({ user, roles, isAuthenticated: true, isBootstrapping: false }),
22	  clearAuth: () => set({ user: null, roles: [], isAuthenticated: false, isBootstrapping: false }),
23	  hasRole: (role) => get().roles.includes(role),
24	  bootstrap: async () => {
25	    try {
26	      const { data } = await me();
27	      set({ user: data.user, roles: data.roles, isAuthenticated: true, isBootstrapping: false });
28	    } catch {
29	      set({ user: null, roles: [], isAuthenticated: false, isBootstrapping: false });
30	    }
31	  },
32	}));
