21		DatabaseURL   string `json:"database_url"`
22		JWTSigningKey string `json:"jwt_signing_key"`
23		AESMasterKey  string `json:"aes_master_key"`
24	}
25	
26	func Load() (*Config, error) {
27		listenAddr := os.Getenv("LISTEN_ADDR")
28		if listenAddr == "" {
29			listenAddr = ":8080"
30		}
31	
32		keyfile := os.Getenv("SECRETS_KEYFILE")
33		if keyfile != "" {
34			return loadFromKeyfile(listenAddr, keyfile)
35		}
36	
37		// Plaintext env vars are only allowed when APP_ENV is explicitly set
38		// to "development". All other values (including unset) require an
39		// encrypted keyfile to prevent accidental secret exposure.
40		appEnv := os.Getenv("APP_ENV")
41		if appEnv != "development" {
42			return nil, fmt.Errorf("SECRETS_KEYFILE is required when APP_ENV=%q; plaintext env vars are only allowed when APP_ENV is explicitly set to 'development'", appEnv)
43		}
44	
45		return loadFromEnv(listenAddr)
46	}
47	
48	func loadFromEnv(listenAddr string) (*Config, error) {
49		dbURL := os.Getenv("DATABASE_URL")
50		if dbURL == "" {
51			return nil, fmt.Errorf("DATABASE_URL is required")
52		}
53	
54		jwtKey := os.Getenv("JWT_SIGNING_KEY")
55		if jwtKey == "" {
56			return nil, fmt.Errorf("JWT_SIGNING_KEY is required")
57		}
58	
59		aesKey, err := decodeAESKey(os.Getenv("AES_MASTER_KEY"))
60		if err != nil {
61			return nil, err
62		}
63	
64		return &Config{
65			ListenAddr:    listenAddr,
66			DatabaseURL:   dbURL,
67			JWTSigningKey: []byte(jwtKey),
68			AESMasterKey:  aesKey,
69		}, nil
70	}
71	
72	func loadFromKeyfile(listenAddr, path string) (*Config, error) {
73		passphrase := os.Getenv("SECRETS_PASSPHRASE")
74		if passphrase == "" {
75			return nil, fmt.Errorf("SECRETS_PASSPHRASE is required when using SECRETS_KEYFILE")
76		}
77	
78		// Validate keyfile permissions: reject world-readable or group-readable files.
79		info, err := os.Stat(path)
80		if err != nil {
81			return nil, fmt.Errorf("stat keyfile %s: %w", path, err)
82		}
83		if mode := info.Mode().Perm(); mode&0o077 != 0 {
84			return nil, fmt.Errorf("keyfile %s has insecure permissions %04o; must be owner-only (0600)", path, mode)
85		}
86	
87		ciphertext, err := os.ReadFile(path)
88		if err != nil {
89			return nil, fmt.Errorf("read keyfile %s: %w", path, err)
90		}
91	
92		plaintext, err := decryptKeyfile(ciphertext, passphrase)
93		if err != nil {
94			return nil, fmt.Errorf("decrypt keyfile: %w", err)
95		}
96	
97		var secrets secretsFile
98		if err := json.Unmarshal(plaintext, &secrets); err != nil {
99			return nil, fmt.Errorf("parse keyfile JSON: %w", err)
100		}
101	
102		if secrets.DatabaseURL == "" || secrets.JWTSigningKey == "" || secrets.AESMasterKey == "" {
103			return nil, fmt.Errorf("keyfile must contain database_url, jwt_signing_key, and aes_master_key")
104		}
105	
106		aesKey, err := decodeAESKey(secrets.AESMasterKey)
107		if err != nil {
108			return nil, err
109		}
110	
111		return &Config{
112			ListenAddr:    listenAddr,
113			DatabaseURL:   secrets.DatabaseURL,
114			JWTSigningKey: []byte(secrets.JWTSigningKey),
115			AESMasterKey:  aesKey,
116		}, nil
117	}
118	
119	func decryptKeyfile(ciphertext []byte, passphrase string) ([]byte, error) {
120		key := sha256.Sum256([]byte(passphrase))
121		block, err := aes.NewCipher(key[:])
122		if err != nil {
123			return nil, err
124		}
125		gcm, err := cipher.NewGCM(block)
126		if err != nil {
127			return nil, err
128		}
129		nonceSize := gcm.NonceSize()
130		if len(ciphertext) < nonceSize {
131			return nil, fmt.Errorf("keyfile too short")
132		}
133		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
134		return gcm.Open(nil, nonce, ct, nil)
135	}
136	
137	func decodeAESKey(hexStr string) ([]byte, error) {
138		if hexStr == "" {
139			return nil, fmt.Errorf("AES_MASTER_KEY is required")
140		}
141		aesKey, err := hex.DecodeString(hexStr)
142		if err != nil {
143			return nil, fmt.Errorf("AES_MASTER_KEY must be hex-encoded: %w", err)
144		}
145		if len(aesKey) != 32 {
146			return nil, fmt.Errorf("AES_MASTER_KEY must be 32 bytes (64 hex chars), got %d bytes", len(aesKey))
147		}
148		return aesKey, nil
149	}
