1	// Unit tests for input validation rules matching backend/internal/dto/request.go.
2	import { describe, it, expect } from 'vitest';
3	
4	const RULES = {
5	  username:              { min: 3, max: 100, required: true },
6	  password:              { min: 8, max: 128, required: true },
7	  display_name:          { max: 200, required: true },
8	  email:                 { pattern: /^[^@]+@[^@]+\.[^@]+$/, required: false },
9	  title:                 { max: 300, required: true },
10	  description:           { max: 5000, required: false },
11	  currency:              { exactLen: 3, required: false },
