14	  hide_reason:           { max: 500, required: true },
15	  message_body:          { max: 5000, required: true },
16	  role_name:             { allowed: ['buyer', 'seller', 'administrator', 'compliance_analyst'], required: true },
17	  ip_action:             { allowed: ['allow', 'deny'], required: true },
18	  traffic_pct:           { min: 1, max: 100, required: true },
19	  rollback_threshold_pct:{ min: 1, max: 100, required: true },
20	  price_cents:           { min: 1, required: true },
21	};
22	
23	function validateLength(value, rules) {
24	  if (rules.required && !value) return false;
25	  if (!value && !rules.required) return true;
26	  if (rules.min !== undefined && value.length < rules.min) return false;
27	  if (rules.max !== undefined && value.length > rules.max) return false;
28	  if (rules.exactLen !== undefined && value.length !== rules.exactLen) return false;
29	  if (rules.pattern && !rules.pattern.test(value)) return false;
30	  if (rules.allowed && !rules.allowed.includes(value)) return false;
31	  return true;
32	}
33	
34	function validateNumeric(value, rules) {
35	  if (rules.required && value == null) return false;
36	  if (value == null && !rules.required) return true;
37	  if (rules.min !== undefined && value < rules.min) return false;
38	  if (rules.max !== undefined && value > rules.max) return false;
39	  return true;
40	}
41	
42	describe('Username', () => {
43	  it('valid',          () => expect(validateLength('admin', RULES.username)).toBe(true));
44	  it('min boundary ok',() => expect(validateLength('abc', RULES.username)).toBe(true));
45	  it('below min',      () => expect(validateLength('ab', RULES.username)).toBe(false));
46	  it('max boundary ok',() => expect(validateLength('a'.repeat(100), RULES.username)).toBe(true));
47	  it('above max',      () => expect(validateLength('a'.repeat(101), RULES.username)).toBe(false));
48	  it('required',       () => expect(validateLength('', RULES.username)).toBe(false));
