54	  it('below min',      () => expect(validateLength('1234567', RULES.password)).toBe(false));
55	  it('max boundary',   () => expect(validateLength('a'.repeat(128), RULES.password)).toBe(true));
56	  it('above max',      () => expect(validateLength('a'.repeat(129), RULES.password)).toBe(false));
57	});
