3	
4	const ERROR_CODES = {
5	  ERR_NOT_FOUND:           404,
6	  ERR_FORBIDDEN:           403,
7	  ERR_UNAUTHORIZED:        401,
8	  ERR_CONFLICT:            409,
9	  ERR_RATE_LIMITED:        429,
10	  ERR_VALIDATION:          422,
11	  ERR_ACCOUNT_LOCKED:      423,
12	  ERR_INVALID_CREDENTIALS: 401,
13	  ERR_ATTACHMENT_TOO_LARGE:413,
14	  ERR_ORDER_DUPLICATE:     409,
15	  ERR_INVALID_TRANSITION:  422,
16	  ERR_OVERSOLD:            409,
17	  ERR_INTERNAL:            500,
18	};
19	
20	// ERR_INTERNAL (500) is a fallback for unmatched errors. It must never be returned
21	// for known business-logic failures (those map to 4xx). The set below lists codes
22	// the API is allowed to return; 500 is here only for the catch-all default path.
23	const VALID_HTTP = new Set([400, 401, 403, 404, 409, 413, 422, 423, 429, 500]);
24	
25	describe('Error Code → HTTP Status Mapping', () => {
26	  it.each(Object.entries(ERROR_CODES))('%s → %i', (code, status) => {
27	    expect(VALID_HTTP.has(status)).toBe(true);
28	  });
29	
30	  it('ERR_NOT_FOUND → 404',           () => expect(ERROR_CODES.ERR_NOT_FOUND).toBe(404));
31	  it('ERR_FORBIDDEN → 403',           () => expect(ERROR_CODES.ERR_FORBIDDEN).toBe(403));
32	  it('ERR_UNAUTHORIZED → 401',        () => expect(ERROR_CODES.ERR_UNAUTHORIZED).toBe(401));
33	  it('ERR_ACCOUNT_LOCKED → 423',      () => expect(ERROR_CODES.ERR_ACCOUNT_LOCKED).toBe(423));
34	  it('ERR_INVALID_CREDENTIALS → 401', () => expect(ERROR_CODES.ERR_INVALID_CREDENTIALS).toBe(401));
35	  it('ERR_ATTACHMENT_TOO_LARGE → 413', () => expect(ERROR_CODES.ERR_ATTACHMENT_TOO_LARGE).toBe(413));
36	  it('ERR_OVERSOLD → 409',            () => expect(ERROR_CODES.ERR_OVERSOLD).toBe(409));
37	  it('ERR_INTERNAL is 500 (catch-all only)', () => expect(ERROR_CODES.ERR_INTERNAL).toBe(500));
38	
39	  it('all known business errors map to 4xx, not 500', () => {
40	    const businessCodes = { ...ERROR_CODES };
41	    delete businessCodes.ERR_INTERNAL;
42	    for (const [code, status] of Object.entries(businessCodes)) {
43	      expect(status, `${code} should be 4xx`).toBeGreaterThanOrEqual(400);
44	      expect(status, `${code} should be 4xx`).toBeLessThan(500);
45	    }
