9	// FNV-1a 32-bit hash matching Go's hash/fnv.
10	// Cross-language contract — no JS production counterpart exists.
11	function fnv32a(buf) {
12	  const FNV_PRIME = 0x01000193;
13	  let h = 0x811C9DC5;
14	  for (let i = 0; i < buf.length; i++) {
15	    h ^= buf[i];
16	    h = Math.imul(h, FNV_PRIME) >>> 0;
17	  }
18	  return h >>> 0;
19	}
20	
21	function assignVariant(userId, testName, trafficPct) {
22	  const data = new TextEncoder().encode(userId + testName);
23	  const h = fnv32a(data);
24	  return (h % 100) < trafficPct ? 'test' : 'control';
25	}
