3	// ExperimentComponent defines a registered UI component that supports A/B
4	// testing. Every experiment name must match an entry here, and variant names
5	// must be drawn from the component's allowed set.
6	type ExperimentComponent struct {
7		// Description is a human-readable summary shown in the admin UI.
8		Description string
9		// AllowedVariants maps variant name → short description.
10		// The map must contain at least two entries (control + test).
11		AllowedVariants map[string]string
12	}
13	
14	// ExperimentRegistry maps experiment names to the UI components they control.
15	// Adding a new A/B-testable component requires registering it here AND
16	// implementing the corresponding frontend branch.
17	var ExperimentRegistry = map[string]ExperimentComponent{
18		"catalog_layout": {
19			Description: "Controls the collectible catalog grid layout (CatalogPage.tsx)",
20			AllowedVariants: map[string]string{
21				"grid": "Multi-column responsive grid (default)",
22				"list": "Single-column list layout",
23			},
24		},
25	}
26	
27	// ValidateExperiment checks that the experiment name and both variant names
28	// are present in the registry. Returns an empty string on success, or a
29	// human-readable error message on failure.
30	func ValidateExperiment(name, controlVariant, testVariant string) string {
31		comp, ok := ExperimentRegistry[name]
32		if !ok {
33			allowed := make([]string, 0, len(ExperimentRegistry))
34			for k := range ExperimentRegistry {
35				allowed = append(allowed, k)
36			}
37			return "unknown experiment name '" + name + "'; registered experiments: " + joinStrings(allowed)
38		}
39	
40		if _, ok := comp.AllowedVariants[controlVariant]; !ok {
41			return "control variant '" + controlVariant + "' is not registered for experiment '" + name + "'; allowed: " + joinStrings(variantKeys(comp))
42		}
43		if _, ok := comp.AllowedVariants[testVariant]; !ok {
44			return "test variant '" + testVariant + "' is not registered for experiment '" + name + "'; allowed: " + joinStrings(variantKeys(comp))
45		}
46		if controlVariant == testVariant {
47			return "control and test variants must be different"
48		}
49		return ""
50	}
51	
52	func variantKeys(c ExperimentComponent) []string {
53		keys := make([]string, 0, len(c.AllowedVariants))
54		for k := range c.AllowedVariants {
55			keys = append(keys, k)
56		}
57		return keys
58	}
59	
60	func joinStrings(ss []string) string {
61		if len(ss) == 0 {
62			return "(none)"
63		}
64		out := ss[0]
65		for _, s := range ss[1:] {
66			out += ", " + s
67		}
68		return out
69	}
