1	package middleware
2	
3	import (
4		"crypto/rand"
5		"encoding/hex"
6		"net/http"
7	
8		"github.com/labstack/echo/v4"
9		"github.com/ledgermint/platform/internal/dto"
10	)
11	
12	func CSRF() echo.MiddlewareFunc {
13		return func(next echo.HandlerFunc) echo.HandlerFunc {
14			return func(c echo.Context) error {
15				// Skip for safe methods
16				if c.Request().Method == http.MethodGet ||
17					c.Request().Method == http.MethodHead ||
18					c.Request().Method == http.MethodOptions {
19					return next(c)
20				}
21	
22				// Skip CSRF for login only (pre-auth, no cookies yet).
23				// Refresh is protected: the client has a csrf_token cookie from login.
24				path := c.Request().URL.Path
25				if path == "/api/auth/login" {
26					return next(c)
27				}
28	
29				cookie, err := c.Cookie("csrf_token")
30				if err != nil {
31					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
32						Error: dto.ErrorDetail{
33							Code:      dto.CodeForbidden,
34							Message:   "missing CSRF cookie",
35							RequestID: GetRequestID(c),
36						},
37					})
38				}
39	
40				header := c.Request().Header.Get("X-CSRF-Token")
41				if header == "" || header != cookie.Value {
42					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
43						Error: dto.ErrorDetail{
44							Code:      dto.CodeForbidden,
45							Message:   "CSRF token mismatch",
46							RequestID: GetRequestID(c),
47						},
48					})
49				}
50	
51				return next(c)
52			}
53		}
54	}
55	
56	func GenerateCSRFToken() (string, error) {
57		b := make([]byte, 32)
58		if _, err := rand.Read(b); err != nil {
59			return "", err
60		}
61		return hex.EncodeToString(b), nil
62	}
63	
64	func SetCSRFCookie(c echo.Context, token string) {
65		c.SetCookie(&http.Cookie{
66			Name:     "csrf_token",
67			Value:    token,
68			Path:     "/",
69			HttpOnly: false, // Must be readable by JS
70			Secure:   false, // LAN - no TLS
71			SameSite: http.SameSiteStrictMode,
72		})
73	}
