137	// DownloadAttachment serves an attachment file by message ID. The internal
138	// filesystem path is never exposed to the client — only the opaque message
139	// UUID is needed to fetch the file.
140	func (h *MessageHandler) DownloadAttachment(c echo.Context) error {
141		msgID, err := uuid.Parse(c.Param("messageId"))
142		if err != nil {
143			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid message ID")
144		}
145	
146		userID, err := uuid.Parse(middleware.GetUserID(c))
147		if err != nil {
148			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
149		}
150	
151		msg, err := h.messageService.GetByID(c.Request().Context(), msgID, userID)
152		if err != nil {
153			return mapError(c, err)
154		}
155	
156		if msg.AttachmentPath == "" {
157			return errorResponse(c, http.StatusNotFound, dto.CodeNotFound, "no attachment on this message")
158		}
159	
160		return c.File(msg.AttachmentPath)
161	}
