163	// isTextAttachment returns true for file types whose content should be scanned as text.
164	func isTextAttachment(mime string, ext string) bool {
165		if strings.HasPrefix(mime, "text/") {
166			return true
167		}
168		ext = strings.ToLower(ext)
169		return ext == ".csv" || ext == ".txt"
170	}
