19	func StructuredLogger(logger *zap.Logger) echo.MiddlewareFunc {
20		return func(next echo.HandlerFunc) echo.HandlerFunc {
21			return func(c echo.Context) error {
22				start := time.Now()
23				err := next(c)
24				latency := time.Since(start)
25	
26				req := c.Request()
27	
28				// Prefer the request-scoped logger (already has request_id),
29				// fall back to the base logger with an explicit field.
30				log := Logger(c)
31				if log == nil {
32					log = logger.With(zap.String("request_id", GetRequestID(c)))
33				}
34	
35				fields := []zap.Field{
36					zap.String("method", req.Method),
37					zap.String("path", req.URL.Path),
38					zap.Int("status", c.Response().Status),
39					zap.Duration("latency", latency),
40					zap.String("remote_ip", c.RealIP()),
41				}
42	
43				if userID, ok := c.Get("user_id").(string); ok {
44					fields = append(fields, zap.String("user_id", userID))
45				}
46	
47				if err != nil {
48					fields = append(fields, zap.Error(err))
49				}
50	
51				status := c.Response().Status
52				switch {
53				case status >= 500:
54					log.Error("request", fields...)
55				case status >= 400:
56					log.Warn("request", fields...)
57				default:
58					log.Info("request", fields...)
59				}
60	
61				return err
62			}
63		}
64	}
