1	package handler
2	
3	import (
4		"bytes"
5		"io"
6		"net/http"
7		"os"
8		"path/filepath"
9		"strings"
10	
11		"github.com/google/uuid"
12		"github.com/labstack/echo/v4"
13		"github.com/ledgermint/platform/internal/dto"
14		"github.com/ledgermint/platform/internal/middleware"
15		"github.com/ledgermint/platform/internal/service"
16	)
17	
18	type MessageHandler struct {
19		messageService *service.MessageService
20		uploadDir      string
21	}
22	
23	func NewMessageHandler(ms *service.MessageService, uploadDir string) *MessageHandler {
24		return &MessageHandler{messageService: ms, uploadDir: uploadDir}
25	}
26	
27	func (h *MessageHandler) List(c echo.Context) error {
28		orderID, err := uuid.Parse(c.Param("orderId"))
29		if err != nil {
30			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
31		}
32	
33		userID, err := uuid.Parse(middleware.GetUserID(c))
34		if err != nil {
35			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
36		}
37	
38		page, pageSize := pagination(c)
39		messages, total, err := h.messageService.ListByOrder(c.Request().Context(), orderID, userID, page, pageSize)
40		if err != nil {
41			return mapError(c, err)
42		}
43		return paginatedResponse(c, messages, page, pageSize, total)
44	}
45	
46	func (h *MessageHandler) Send(c echo.Context) error {
47		orderID, err := uuid.Parse(c.Param("orderId"))
48		if err != nil {
49			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
50		}
51	
52		userID, err := uuid.Parse(middleware.GetUserID(c))
53		if err != nil {
54			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
55		}
56	
57		body := c.FormValue("body")
58		if body == "" {
59			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body is required")
60		}
61	
62		// Server-side PII detection
63		if detected, piiTypes := service.DetectPII(body); detected {
64			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, service.PIIErrorMessage(piiTypes))
65		}
66	
67		var attachmentPath, attachmentMime string
68		var attachmentSize int
69	
70		file, err := c.FormFile("attachment")
71		if err == nil {
72			// Server-side 10MB enforcement
73			if file.Size > service.MaxAttachmentSize {
74				return errorResponse(c, http.StatusRequestEntityTooLarge, dto.CodeAttachmentTooLarge, "attachment exceeds 10MB limit")
75			}
76	
77			src, err := file.Open()
78			if err != nil {
79				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
80			}
81			defer src.Close()
82	
83			mime := file.Header.Get("Content-Type")
84			ext := filepath.Ext(file.Filename)
85	
86			// PII scan: read the attachment into memory so we can inspect it
87			// before persisting to disk. Text-based files are scanned directly;
88			// non-text files are checked against an allowlist of safe binary
89			// MIME types — anything that is neither scannable text nor an
90			// approved binary type is rejected.
91			buf := &bytes.Buffer{}
92			if _, err := io.Copy(buf, src); err != nil {
93				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
94			}
95	
96			if isTextAttachment(mime, ext) {
97				if detected, piiTypes := service.DetectPII(buf.String()); detected {
98					c.Logger().Warn("attachment PII blocked for order ", orderID.String())
99					return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
100						"attachment blocked: contains sensitive personal information ("+strings.Join(piiTypes, ", ")+")")
101				}
102			} else if !isSafeBinaryAttachment(mime, ext) {
103				return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
104					"attachment type not allowed: "+mime+" ("+ext+"); supported types: images, PDF, plain text, CSV")
105			}
106	
107			dir := filepath.Join(h.uploadDir, orderID.String())
108			if err := os.MkdirAll(dir, 0o755); err != nil {
109				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to create upload directory")
110			}
111	
112			filename := uuid.New().String() + ext
113			dstPath := filepath.Join(dir, filename)
114	
115			dst, err := os.Create(dstPath)
116			if err != nil {
117				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to save attachment")
118			}
119			defer dst.Close()
120	
121			if _, err := io.Copy(dst, buf); err != nil {
122				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
123			}
124	
125			attachmentPath = dstPath
126			attachmentSize = int(file.Size)
127			attachmentMime = mime
128		}
129	
130		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
131			attachmentPath, attachmentSize, attachmentMime)
132		if err != nil {
133			return mapError(c, err)
134		}
135		return c.JSON(http.StatusCreated, msg)
136	}
137	
138	// DownloadAttachment serves an attachment file by message ID. The internal
139	// filesystem path is never exposed to the client — only the opaque message
140	// UUID is needed to fetch the file.
141	func (h *MessageHandler) DownloadAttachment(c echo.Context) error {
142		msgID, err := uuid.Parse(c.Param("messageId"))
143		if err != nil {
144			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid message ID")
145		}
146	
147		userID, err := uuid.Parse(middleware.GetUserID(c))
148		if err != nil {
149			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
150		}
151	
152		msg, err := h.messageService.GetByID(c.Request().Context(), msgID, userID)
153		if err != nil {
154			return mapError(c, err)
155		}
156	
157		if msg.AttachmentPath == "" {
158			return errorResponse(c, http.StatusNotFound, dto.CodeNotFound, "no attachment on this message")
159		}
160	
161		return c.File(msg.AttachmentPath)
162	}
163	
164	// isTextAttachment returns true for file types whose content should be scanned as text.
165	func isTextAttachment(mime string, ext string) bool {
166		if strings.HasPrefix(mime, "text/") {
167			return true
168		}
169		ext = strings.ToLower(ext)
170		return ext == ".csv" || ext == ".txt"
171	}
172	
173	// safeBinaryMIMEs lists binary MIME types that are allowed as attachments.
174	// These formats cannot be meaningfully scanned for PII as plain text, but
175	// are common enough in a collectibles exchange that blocking them would
176	// break legitimate workflows (proof-of-authenticity photos, certificates, etc.).
177	var safeBinaryMIMEs = map[string]bool{
178		"image/jpeg":      true,
179		"image/png":       true,
180		"image/gif":       true,
181		"image/webp":      true,
182		"image/svg+xml":   true,
183		"application/pdf": true,
184	}
185	
186	// safeBinaryExts provides a fallback when the MIME type from the client
187	// is generic (e.g. application/octet-stream).
188	var safeBinaryExts = map[string]bool{
189		".jpg": true, ".jpeg": true, ".png": true, ".gif": true,
190		".webp": true, ".svg": true, ".pdf": true,
191	}
192	
193	// isSafeBinaryAttachment returns true for binary file types that are
194	// explicitly allowed. Anything not on this list and not scannable as text
195	// is rejected, preventing unscannable formats (DOCX, XLSX, etc.) from
196	// bypassing PII checks.
197	func isSafeBinaryAttachment(mime string, ext string) bool {
198		if safeBinaryMIMEs[mime] {
199			return true
200		}
201		return safeBinaryExts[strings.ToLower(ext)]
202	}
203	
