1	package handler
2	
3	import (
4		"bytes"
5		"io"
6		"net/http"
7		"os"
8		"path/filepath"
9		"strings"
10	
11		"github.com/google/uuid"
12		"github.com/labstack/echo/v4"
13		"github.com/ledgermint/platform/internal/dto"
14		"github.com/ledgermint/platform/internal/middleware"
15		"github.com/ledgermint/platform/internal/service"
16	)
17	
18	type MessageHandler struct {
19		messageService *service.MessageService
20		uploadDir      string
21	}
22	
23	func NewMessageHandler(ms *service.MessageService, uploadDir string) *MessageHandler {
24		return &MessageHandler{messageService: ms, uploadDir: uploadDir}
25	}
26	
27	func (h *MessageHandler) List(c echo.Context) error {
28		orderID, err := uuid.Parse(c.Param("orderId"))
29		if err != nil {
30			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
31		}
32	
33		userID, err := uuid.Parse(middleware.GetUserID(c))
34		if err != nil {
35			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
36		}
37	
38		page, pageSize := pagination(c)
39		messages, total, err := h.messageService.ListByOrder(c.Request().Context(), orderID, userID, page, pageSize)
40		if err != nil {
41			return mapError(c, err)
42		}
43		return paginatedResponse(c, messages, page, pageSize, total)
44	}
45	
46	func (h *MessageHandler) Send(c echo.Context) error {
47		orderID, err := uuid.Parse(c.Param("orderId"))
48		if err != nil {
49			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
50		}
51	
52		userID, err := uuid.Parse(middleware.GetUserID(c))
53		if err != nil {
54			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
55		}
56	
57		body := c.FormValue("body")
58		if body == "" {
59			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body is required")
60		}
61	
62		// Server-side PII detection
63		if detected, piiTypes := service.DetectPII(body); detected {
64			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, service.PIIErrorMessage(piiTypes))
65		}
66	
67		var attachmentPath, attachmentMime string
68		var attachmentSize int
69	
70		file, err := c.FormFile("attachment")
71		if err == nil {
72			// Server-side 10MB enforcement
73			if file.Size > service.MaxAttachmentSize {
74				return errorResponse(c, http.StatusRequestEntityTooLarge, dto.CodeAttachmentTooLarge, "attachment exceeds 10MB limit")
75			}
76	
77			src, err := file.Open()
78			if err != nil {
79				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
80			}
81			defer src.Close()
82	
83			mime := file.Header.Get("Content-Type")
84			ext := filepath.Ext(file.Filename)
85	
86			// Read the full attachment into memory before persisting so we can
87			// inspect it for PII regardless of format.
88			buf := &bytes.Buffer{}
89			if _, err := io.Copy(buf, src); err != nil {
90				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
91			}
92	
93			// Reject file types that are neither scannable text nor an
94			// approved binary type (images, PDF, SVG).
95			if !isTextAttachment(mime, ext) && !isSafeBinaryAttachment(mime, ext) {
96				return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
97					"attachment type not allowed: "+mime+" ("+ext+"); supported types: images, PDF, plain text, CSV")
98			}
99	
100			// PII scan — applied to ALL attachments, not just text files.
101			// For text files this is a direct content scan. For binary
102			// formats (PDF, SVG, images) the raw bytes are scanned: PII
103			// patterns like SSNs, phone numbers, and emails are detectable
104			// in uncompressed content (PDF text streams, SVG XML, EXIF
105			// metadata). Raster images rarely contain regex-matchable PII
106			// in their raw bytes, so they pass through harmlessly while
107			// still being checked.
108			if detected, piiTypes := service.DetectPII(buf.String()); detected {
109				c.Logger().Warn("attachment PII blocked for order ", orderID.String())
110				return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
111					"attachment blocked: contains sensitive personal information ("+strings.Join(piiTypes, ", ")+")")
112			}
113	
114			dir := filepath.Join(h.uploadDir, orderID.String())
115			if err := os.MkdirAll(dir, 0o755); err != nil {
116				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to create upload directory")
117			}
118	
119			filename := uuid.New().String() + ext
120			dstPath := filepath.Join(dir, filename)
121	
122			dst, err := os.Create(dstPath)
123			if err != nil {
124				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to save attachment")
125			}
126			defer dst.Close()
127	
128			if _, err := io.Copy(dst, buf); err != nil {
129				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
130			}
131	
132			attachmentPath = dstPath
133			attachmentSize = int(file.Size)
134			attachmentMime = mime
135		}
136	
137		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
138			attachmentPath, attachmentSize, attachmentMime)
139		if err != nil {
140			return mapError(c, err)
141		}
142		return c.JSON(http.StatusCreated, msg)
143	}
144	
145	// DownloadAttachment serves an attachment file by message ID. The internal
146	// filesystem path is never exposed to the client — only the opaque message
147	// UUID is needed to fetch the file.
148	func (h *MessageHandler) DownloadAttachment(c echo.Context) error {
149		msgID, err := uuid.Parse(c.Param("messageId"))
150		if err != nil {
151			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid message ID")
152		}
153	
154		userID, err := uuid.Parse(middleware.GetUserID(c))
155		if err != nil {
156			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
157		}
158	
159		msg, err := h.messageService.GetByID(c.Request().Context(), msgID, userID)
160		if err != nil {
161			return mapError(c, err)
162		}
163	
164		if msg.AttachmentPath == "" {
165			return errorResponse(c, http.StatusNotFound, dto.CodeNotFound, "no attachment on this message")
166		}
167	
168		return c.File(msg.AttachmentPath)
169	}
170	
171	// isTextAttachment returns true for file types whose content should be scanned as text.
172	func isTextAttachment(mime string, ext string) bool {
173		if strings.HasPrefix(mime, "text/") {
174			return true
175		}
176		ext = strings.ToLower(ext)
177		return ext == ".csv" || ext == ".txt"
178	}
179	
180	// safeBinaryMIMEs lists binary MIME types that are allowed as attachments.
181	// These formats cannot be meaningfully scanned for PII as plain text, but
182	// are common enough in a collectibles exchange that blocking them would
183	// break legitimate workflows (proof-of-authenticity photos, certificates, etc.).
184	var safeBinaryMIMEs = map[string]bool{
185		"image/jpeg":      true,
186		"image/png":       true,
187		"image/gif":       true,
188		"image/webp":      true,
189		"image/svg+xml":   true,
190		"application/pdf": true,
191	}
192	
193	// safeBinaryExts provides a fallback when the MIME type from the client
194	// is generic (e.g. application/octet-stream).
